import json, re, sys

schema_path = 'config/schemas/revision_packet.schema.json'
with open(schema_path) as f:
    schema = json.load(f)

required_top = schema['required']
finding_required = schema['properties']['findings']['items']['required']

packets = [
    'manual_rescue/packets/chapter_06.revision_packet.json',
    'manual_rescue/packets/chapter_07.revision_packet.json',
    'manual_rescue/packets/chapter_10.revision_packet.json',
    'manual_rescue/packets/chapter_11.revision_packet.json',
    'manual_rescue/packets/chapter_12.revision_packet.json',
]

for p in packets:
    with open(p) as f:
        data = json.load(f)
    errors = []
    # Check required top-level fields
    for r in required_top:
        if r not in data:
            errors.append(f'Missing top-level field: {r}')
    # Check chapter_id pattern
    if not re.match(r'^chapter_[0-9]{2}$', data.get('chapter_id', '')):
        errors.append(f'Bad chapter_id: {data.get(\"chapter_id\")}')
    # Check cycle
    if not isinstance(data.get('cycle'), int) or data['cycle'] < 1:
        errors.append(f'Bad cycle: {data.get(\"cycle\")}')
    # Check hash
    if not re.match(r'^[a-f0-9]{64}$', data.get('input_snapshot_hash', '')):
        errors.append(f'Bad hash: {data.get(\"input_snapshot_hash\")}')
    # Check must_fix_count
    if not isinstance(data.get('must_fix_count'), int) or data['must_fix_count'] < 0:
        errors.append(f'Bad must_fix_count')
    # Check arrays
    for arr_key in ['non_negotiables', 'acceptance_targets']:
        if not isinstance(data.get(arr_key), list) or not all(isinstance(s, str) and len(s) > 0 for s in data[arr_key]):
            errors.append(f'Bad {arr_key}')
    # Check findings
    for i, finding in enumerate(data.get('findings', [])):
        for r in finding_required:
            if r not in finding:
                errors.append(f'Finding {i} missing: {r}')
        if not re.match(r'^chapter_[0-9]{2}$', finding.get('chapter_id', '')):
            errors.append(f'Finding {i} bad chapter_id')
        valid_sev = ['MEDIUM', 'HIGH', 'CRITICAL']
        if finding.get('severity') not in valid_sev:
            errors.append(f'Finding {i} bad severity: {finding.get(\"severity\")}')

    status = 'VALID' if not errors else 'INVALID'
    print(f'{p.split(\"/\")[-1]}: {status}')
    for e in errors:
        print(f'  - {e}')
"
